document.addEventListener("DOMContentLoaded",async()=>{const t=document.getElementById("statusBadge"),e=document.getElementById("otpView"),n=document.getElementById("unpairedView"),o=document.getElementById("otpValue"),s=document.getElementById("otpTime"),d=document.getElementById("copyBtn"),a=document.getElementById("pairBtn"),i=document.getElementById("signOutBtn");function c(){t.textContent="Disconnected",t.className="status status-unpaired",e.classList.add("hidden"),n.classList.remove("hidden")}function m(t){o.textContent=t.otp,s.textContent="Received at "+new Date(t.ts).toLocaleTimeString()}chrome.runtime.sendMessage({type:"getStatus"},o=>{"paired"===o.status?(t.textContent="Connected",t.className="status status-paired",e.classList.remove("hidden"),n.classList.add("hidden")):c()}),chrome.storage.local.get(["latestOtp"],({latestOtp:t})=>{t&&m(t)}),a.onclick=()=>{window.open("pairing.html")},d.onclick=()=>{navigator.clipboard.writeText(o.textContent);const t=d.textContent;d.textContent="Copied!",setTimeout(()=>d.textContent=t,1500)},i.onclick=()=>{chrome.runtime.sendMessage({type:"signOut"},()=>{c()})},chrome.runtime.onMessage.addListener(t=>{"newOtp"===t.type&&m({otp:t.otp,ts:Date.now()})})});